import PropTypes from 'prop-types';
import React, {useCallback, useEffect, useMemo, useState} from 'react';
import {semantics} from '@customink/design-tokens';
import {
  PDP_RELATED_PRODUCTS_VIEW_TYPE,
  RELATED_PRODUCTS_TAB_KEY_BUDGET_FRIENDLY,
  RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE,
  RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS
} from 'constants/pdpRelatedProducts';
import useIntersectionObserverOnce from 'hooks/useIntersectionObserverOnce';
import ProductDetailsRow from 'product_details_page/ProductDetailsRow';
import ProductDetailsCard from 'product_details_page/RelatedProducts/RelatedProductCard';
import createRecoCardLinkHref from 'utils/createRecoCardLinkHref';
import {
  EVENT_TYPE,
  fireTabbedViewEvent,
  fireTabbedViewEventWithCallback
} from 'utils/metrics/pdpRelatedStylesTabbedView';
import handleRightClick from 'utils/rightClickForCard';
import {
  CarouselCardsView,
  EmptyStateCardsView,
  Loader,
  StyledRecoBox,
  Tabs
} from './components';

const CardsComponent = ({children, isLoading, length, separatedView}) => {
  if (!isLoading && length === 0) {
    return <EmptyStateCardsView />;
  }
  if (isLoading) {
    return <Loader />;
  }
  if (length <= 4) {
    return <StyledRecoBox>{children}</StyledRecoBox>;
  }

  return (
    <CarouselCardsView separatedView={separatedView}>
      {children}
    </CarouselCardsView>
  );
};

CardsComponent.propTypes = {
  separatedView: PropTypes.bool.isRequired,
  children: PropTypes.node.isRequired,
  isLoading: PropTypes.bool.isRequired,
  length: PropTypes.number.isRequired,
  activeTab: PropTypes.string.isRequired
};

const getWidgetType = (activeTab) => {
  switch (activeTab) {
    case RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE:
      return 'you_may_also_like';
    case RELATED_PRODUCTS_TAB_KEY_BUDGET_FRIENDLY:
      return 'budget_friendly';
    case RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS:
      return 'trending';
    default:
      return 'recommended';
  }
};

const getTitle = (type, activeTab) => {
  if (type === PDP_RELATED_PRODUCTS_VIEW_TYPE.tabbed) {
    return 'Recommended for you';
  }
  switch (activeTab) {
    case RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE:
      return 'Shop Similar Styles';
    case RELATED_PRODUCTS_TAB_KEY_BUDGET_FRIENDLY:
      return 'Budget Friendly Options';
    case RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS:
      return 'Trending Products';
    default:
      break;
  }

  return 'Recommended for you';
};

const RelatedProductsTabbedView = ({
  type = PDP_RELATED_PRODUCTS_VIEW_TYPE.tabbed,
  activeTab = RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE,
  hasAnyData = true,
  isLoading,
  onTabChange,
  products = [],
  relatedProductsRef,
  tabs = []
}) => {
  const [isVisible, setIsVisible] = useState(true);

  useEffect(() => {
    if (!hasAnyData && !isLoading) {
      setIsVisible(false);
    } else if (hasAnyData || isLoading) {
      setIsVisible(true);
    }
  }, [hasAnyData, isLoading]);
  useIntersectionObserverOnce(relatedProductsRef, () => {
    fireTabbedViewEvent({
      eventType: EVENT_TYPE.VIEWED
    });
  });
  const handleCardClick = useCallback(
    (styleId, href) => (event) => {
      fireTabbedViewEventWithCallback({
        callback: () => {
          handleRightClick(event, href);
        },
        eventData: {
          activeTab,
          eventType: EVENT_TYPE.ITEM_CLICKED,
          styleId
        }
      });
    },
    [activeTab]
  );
  const slides = useMemo(
    () =>
      products.map((product) => (
        <ProductDetailsCard
          sx={{
            width: '100%',
            '&:hover': {
              boxShadow: 'none'
            },
            '& .MuiCardContent-root': {
              display: 'flex',
              flex: '1 1 auto',
              flexDirection: 'column',
              gap: `${semantics.units.space.componentLayout.xs} !important`,
              minHeight: '7.5rem !important',
              padding: `${semantics.units.space.componentLayout.sm} ${semantics.units.space.componentLayout.xs} !important`,
              fontFamily: 'SharpSans, sans-serif',
              [`@media (min-width: ${semantics.units.size.breakpoint.desktop})`]:
                {
                  padding: `${semantics.units.space.componentLayout.sm} ${semantics.units.space.componentLayout.md} !important`
                }
            },
            '& .rpc-image-wrapper': {
              flexShrink: 0,
              height: '9rem !important',
              paddingTop: '0 !important',
              width: '100% !important',
              [`@media (min-width: ${semantics.units.size.breakpoint.desktop})`]:
                {
                  height: '13rem !important'
                },
              [`@media (min-width: ${semantics.units.size.breakpoint.desktopXL})`]:
                {
                  height: '18rem !important'
                }
            },
            '& [data-testid="reco-product-name"]': {
              fontFamily: 'SharpSans, sans-serif',
              marginBottom: '0 !important',
              minHeight: '2rem',
              WebkitLineClamp: 2
            },
            '& [data-testid="product-price-container"]': {
              fontFamily: 'SharpSans, sans-serif',
              color: semantics.light.neutral.text.secondary
            },
            span: {
              fontFamily: 'SharpSans, sans-serif'
            },
            height: '19.4rem',
            [`@media (min-width: ${semantics.units.size.breakpoint.desktop}) and (max-width: 1299px)`]:
              {
                height: '23rem'
              },
            [`@media (min-width: ${semantics.units.size.breakpoint.desktopXL})`]:
              {
                height: '27.5rem'
              }
          }}
          key={`related-styles-${activeTab.toLowerCase()}-${product.name}`}
          onClick={handleCardClick(
            product.style_id,
            createRecoCardLinkHref({
              stylePath: product.link,
              colorId: product.color
            })
          )}
          linkHref={createRecoCardLinkHref({
            stylePath: product.link,
            colorId: product.color
          })}
          imageSrc={product.image_src}
          imageSrcSet={product.image_srcset}
          minQty={product.min_qty}
          name={product.name}
          ratingCount={product.rating_count}
          ratingScore={product.rating_score}
          sizing={product.sizing}
          generalComments={product.general_comments}
          defaultUnitPrices={product.default_unit_prices}
          primaryCategoryId={product.primary_category_id}
          styleType={product.style_type}
          defaultQuoteQty={product.default_quote_qty}
          productId={product.style_id}
          widgetType={getWidgetType(activeTab)}
          categories={
            product.categories || [
              {
                id: product.primary_category_id,
                name: product.primary_category_name
              }
            ]
          }
        />
      )),
    [activeTab, handleCardClick, products]
  );

  return (
    <div
      style={{
        maxHeight: isVisible ? '62.5rem' : '0',
        opacity: isVisible ? 1 : 0,
        overflow: 'hidden',
        transition: 'max-height 0.5s ease-out, opacity 0.5s ease-out'
      }}>
      <ProductDetailsRow
        childrenRef={relatedProductsRef}
        title={getTitle(type, activeTab)}>
        <Tabs tabs={tabs} activeTab={activeTab} onTabChange={onTabChange} />
        <CardsComponent
          key={activeTab}
          isLoading={isLoading}
          length={products.length}
          activeTab={activeTab}>
          {slides}
        </CardsComponent>
      </ProductDetailsRow>
    </div>
  );
};

RelatedProductsTabbedView.propTypes = {
  type: PropTypes.string,
  activeTab: PropTypes.string,
  hasAnyData: PropTypes.bool,
  isLoading: PropTypes.bool,
  onTabChange: PropTypes.func,
  products: PropTypes.arrayOf(
    PropTypes.shape({
      color: PropTypes.number,
      general_comments: PropTypes.string,
      image_src: PropTypes.string,
      image_srcset: PropTypes.string,
      link: PropTypes.string,
      min_qty: PropTypes.number,
      name: PropTypes.string,
      rating_count: PropTypes.string,
      rating_score: PropTypes.string,
      sizing: PropTypes.string,
      style_id: PropTypes.number
    })
  ),
  relatedProductsRef: PropTypes.object,
  tabs: PropTypes.arrayOf(
    PropTypes.shape({
      label: PropTypes.string,
      value: PropTypes.string
    })
  )
};

export default RelatedProductsTabbedView;

