import {
  RELATED_PRODUCTS_TAB_KEY_MORE_FITS_AND_SIZES,
  RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE,
  RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS
} from 'constants/pdpRelatedProducts';
import isAlgoliaRecommendations from 'utils/isAlgoliaRecommendations';

export default function useRelatedProductsState({
  breakpoint,
  forceTab,
  isRecommendationsProductsFetched,
  isRecommendationsProductsRefetching,
  isRelatedProductsFetched,
  isRelatedProductsRefetching,
  isTrendingProductsFetched,
  isTrendingProductsRefetching,
  tabs = []
}) {
  const [relatedProductsActiveTab, setRelatedProductsActiveTab] = useState(
    RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE
  );

  const isMobile = breakpoint === 'xs' || breakpoint === 'sm';
  const shouldTabbedViewRender = !isMobile && isAlgoliaRecommendations();

  const tabbedViewIsLoading = useMemo(() => {
    if (
      relatedProductsActiveTab === RELATED_PRODUCTS_TAB_KEY_MORE_FITS_AND_SIZES
    ) {
      return !isRelatedProductsFetched || isRelatedProductsRefetching;
    }

    if (relatedProductsActiveTab === RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS) {
      return !isTrendingProductsFetched || isTrendingProductsRefetching;
    }

    return (
      !isRecommendationsProductsFetched || isRecommendationsProductsRefetching
    );
  }, [
    relatedProductsActiveTab,
    isRecommendationsProductsFetched,
    isRecommendationsProductsRefetching,
    isRelatedProductsFetched,
    isRelatedProductsRefetching,
    isTrendingProductsFetched,
    isTrendingProductsRefetching
  ]);

  const hasAnyData = useMemo(() => {
    return tabs.length > 0;
  }, [tabs.length]);

  useEffect(() => {
    if (tabs.length > 0) {
      const activeTabExists = tabs.some(
        (tab) => tab.value === relatedProductsActiveTab
      );
      if (!activeTabExists) {
        setRelatedProductsActiveTab(tabs[0].value);
      }
      if (forceTab && forceTab !== relatedProductsActiveTab) {
        setRelatedProductsActiveTab(forceTab);
      }
    }
  }, [tabs, relatedProductsActiveTab, forceTab]);

  return {
    hasAnyData,
    relatedProductsActiveTab,
    setRelatedProductsActiveTab,
    shouldTabbedViewRender,
    tabbedViewIsLoading
  };
}

