import {useMemo} from 'react';
import {
  RELATED_PRODUCTS_TAB_KEY_BUDGET_FRIENDLY,
  RELATED_PRODUCTS_TAB_KEY_LOWER_MINIMUMS,
  RELATED_PRODUCTS_TAB_KEY_MORE_FITS_AND_SIZES,
  RELATED_PRODUCTS_TAB_KEY_MORE_FROM_THIS_BRAND,
  RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE,
  RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS,
  RELATED_PRODUCTS_TABS
} from 'constants/pdpRelatedProducts';
import {filterByCategory} from './useRelatedProductsData';

export default function useRelatedProductsTabs({
  forceTab,
  isApparel,
  isNoMinimumSelected,
  isRecommendationsProductsFetched,
  isRelatedProductsFetched,
  minQty,
  primaryCategoryId,
  recoBrandProducts,
  recommendations,
  relatedProducts
}) {
  const tabsToShow = useMemo(
    () =>
      Object.values(RELATED_PRODUCTS_TABS).filter(({value}) => {
        const filteredProducts = filterByCategory(
          recommendations?.related_products,
          primaryCategoryId
        );

        if (value === RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS) {
          return false;
        }
        if (value === RELATED_PRODUCTS_TAB_KEY_MORE_FITS_AND_SIZES) {
          if (isApparel) {
            return (
              !isRelatedProductsFetched ||
              relatedProducts?.complements?.length > 0
            );
          }
          return false;
        }
        if (value === RELATED_PRODUCTS_TAB_KEY_MORE_FROM_THIS_BRAND) {
          return recoBrandProducts?.brand_products?.length > 0;
        }
        if (value === RELATED_PRODUCTS_TAB_KEY_LOWER_MINIMUMS) {
          const lowerMinimumProducts = filteredProducts?.filter(
            (product) => product.min_qty < minQty
          );

          return !isNoMinimumSelected && lowerMinimumProducts?.length > 0;
        }
        return (
          !isRecommendationsProductsFetched || filteredProducts?.length > 0
        );
      }),
    [
      isApparel,
      isNoMinimumSelected,
      isRecommendationsProductsFetched,
      isRelatedProductsFetched,
      minQty,
      primaryCategoryId,
      recoBrandProducts?.brand_products?.length,
      recommendations,
      relatedProducts
    ]
  );

  const tabOrder = useMemo(() => {
    return [
      RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE,
      RELATED_PRODUCTS_TAB_KEY_BUDGET_FRIENDLY,
      ...[
        RELATED_PRODUCTS_TAB_KEY_MORE_FROM_THIS_BRAND,
        RELATED_PRODUCTS_TAB_KEY_MORE_FITS_AND_SIZES,
        RELATED_PRODUCTS_TAB_KEY_LOWER_MINIMUMS
      ].sort(() => Math.random() - 0.5)
    ];
  }, []);

  const tabs = useMemo(() => {
    return tabsToShow.sort((a, b) => {
      return tabOrder.indexOf(a.value) - tabOrder.indexOf(b.value);
    });
  }, [tabsToShow, tabOrder]);

  return {
    tabOrder,
    tabs,
    tabsToShow
  };
}

