import {useTrendingProductsByCategoryId} from './recommendations';

const useTrendingProductsByCategory = ({categoryId, isEnabled}) => {
  const {data, isError, isLoading, isFetched} = useTrendingProductsByCategoryId(
    {
      categoryId,
      isEnabled,
      limit: 20
    }
  );

  if (
    isError ||
    (data && (!data.trendingProducts || data.trendingProducts.length === 0))
  ) {
    return {
      isLoading: false,
      isFetched,
      products: []
    };
  }

  return {
    isLoading,
    isFetched,
    products: data?.trendingProducts ?? []
  };
};

export default useTrendingProductsByCategory;

