import {useMemo} from 'react';
import {
  RELATED_PRODUCTS_TAB_KEY_BUDGET_FRIENDLY,
  RELATED_PRODUCTS_TAB_KEY_LOWER_MINIMUMS,
  RELATED_PRODUCTS_TAB_KEY_MORE_FITS_AND_SIZES,
  RELATED_PRODUCTS_TAB_KEY_MORE_FROM_THIS_BRAND,
  RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS
} from 'constants/pdpRelatedProducts';
import {searchParams} from 'src/utils/url';
import DEFAULT_PRICING_ALGORITHM from 'constants/defaultPriceAlgorithm';
import {
  BLANK_PRICE_QTY,
  unbundledPriceSortEligible
} from 'utils/abTests/unbundledPriceTest';

export const filterByCategory = (products, categoryId) => {
  if (!products || !categoryId) return products;
  const filteredProducts = products.filter(
    (product) => product.primary_category_id === categoryId
  );
  return filteredProducts.length > 0 ? filteredProducts : products;
};

export const filterByBrand = (products, brand) => {
  if (!products) return products;
  if (!brand || brand === '') return [];
  return products.filter((item) =>
    item.brand?.find(
      (recoBrand) =>
        recoBrand !== '' && recoBrand.toLowerCase() === brand.toLowerCase()
    )
  );
};

export const getMinPrice = ({product, useBlankPrice = false}) => {
  const {
    default_unit_prices: defaultUnitPrices,
    minQty,
    default_quote_qty: defaultQuoteQty
  } = product;

  if (useBlankPrice) {
    const blankPriceEntry = defaultUnitPrices.find(
      (price) =>
        price?.quantity === BLANK_PRICE_QTY &&
        price?.algorithm === DEFAULT_PRICING_ALGORITHM &&
        price?.price !== null &&
        price?.price !== undefined
    );
    if (blankPriceEntry) {
      return {price: Number(blankPriceEntry.price)};
    }
    return {price: Number.MAX_SAFE_INTEGER};
  }

  let quoteQtyParam;
  try {
    quoteQtyParam = searchParams()?.get('quote_qty');
  } catch {
    quoteQtyParam = null;
  }

  const useNoMinimum =
    quoteQtyParam === 'min' &&
    minQty === 1 &&
    defaultUnitPrices.find((price) => price?.quantity === 1);

  const expectedQuantity = useNoMinimum ? 1 : defaultQuoteQty;

  if (
    expectedQuantity === null ||
    expectedQuantity === undefined ||
    typeof expectedQuantity !== 'number'
  ) {
    return {price: Number.MAX_SAFE_INTEGER};
  }

  const productPrices = defaultUnitPrices.find(
    (price) =>
      price?.quantity === expectedQuantity &&
      price?.algorithm === DEFAULT_PRICING_ALGORITHM &&
      price?.price !== null &&
      price?.price !== undefined
  );

  if (!productPrices) {
    return {price: Number.MAX_SAFE_INTEGER};
  }

  const {price, regular_unit_price} = productPrices;

  const numPrice = Number(price);
  const numRegularPrice = Number(regular_unit_price);

  if (
    !isNaN(numPrice) &&
    !isNaN(numRegularPrice) &&
    numRegularPrice > 0 &&
    numRegularPrice < numPrice
  ) {
    return {price: numRegularPrice};
  }

  if (!isNaN(numPrice)) {
    return {price: numPrice};
  }

  return {price: Number.MAX_SAFE_INTEGER};
};

export default function useRelatedProductsData({
  alternativeProducts,
  minQty,
  primaryCategoryId,
  recoBrandProducts,
  recommendations,
  relatedProducts,
  relatedProductsActiveTab,
  shouldTabbedViewRender,
  trendingProducts
}) {
  const tabbedViewProducts = useMemo(() => {
    if (!shouldTabbedViewRender) {
      return alternativeProducts.slice(0, 4);
    }

    let products;
    switch (relatedProductsActiveTab) {
      case RELATED_PRODUCTS_TAB_KEY_MORE_FITS_AND_SIZES:
        products = relatedProducts?.complements;
        break;
      case RELATED_PRODUCTS_TAB_KEY_BUDGET_FRIENDLY: {
        const useBlankPrice = unbundledPriceSortEligible(primaryCategoryId);
        products = filterByCategory(
          recommendations?.related_products,
          primaryCategoryId
        );
        if (products) {
          products = [...products].sort(
            (a, b) =>
              getMinPrice({product: a, useBlankPrice}).price -
              getMinPrice({product: b, useBlankPrice}).price
          );
        }
        break;
      }
      case RELATED_PRODUCTS_TAB_KEY_MORE_FROM_THIS_BRAND:
        products = recoBrandProducts?.brand_products || [];
        break;
      case RELATED_PRODUCTS_TAB_KEY_LOWER_MINIMUMS:
        products = filterByCategory(
          recommendations?.related_products,
          primaryCategoryId
        )
          ?.filter((product) => product.min_qty < minQty)
          ?.sort((a, b) => a.min_qty - b.min_qty);
        break;
      case RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS:
        products = trendingProducts;
        break;
      default:
        products = filterByCategory(
          recommendations?.related_products,
          primaryCategoryId
        );
    }
    return products;
  }, [
    alternativeProducts,
    minQty,
    primaryCategoryId,
    recoBrandProducts?.brand_products,
    recommendations,
    relatedProducts,
    relatedProductsActiveTab,
    shouldTabbedViewRender,
    trendingProducts
  ]);

  return {
    filterByBrand,
    filterByCategory,
    getMinPrice,
    tabbedViewProducts
  };
}

