export const CLICK_EVENT = 'module click';
export const DISPLAY_EVENT = 'module display';

export const CLICK_SECTION = 'pdp related items tabbed view';

export const EVENT_TYPE = {
  ARROW_CLICKED: 'ARROW_CLICKED',
  ITEM_CLICKED: 'ITEM_CLICKED',
  TAB_CHANGED: 'TAB_CHANGED',
  VIEWED: 'VIEWED'
};

export const prepareTabbedViewEventData = ({
  activeTab,
  arrowDirection = null,
  ecommerce = {},
  eventType = EVENT_TYPE.VIEWED,
  firstTabChange = false,
  previousTab = null,
  styleId = null
}) => {
  const sharedData = {
    event: 'recommendation_click',
    interaction_category: 'pdp_similar_products',
    interaction_label: 'alternative_related_items_v2',
    ...(ecommerce ? {ecommerce} : {})
  };

  switch (eventType) {
    case EVENT_TYPE.ITEM_CLICKED:
      return {
        ...sharedData,
        active_tab: activeTab,
        interaction_action: CLICK_EVENT,
        product_style_id: styleId
      };
    case EVENT_TYPE.TAB_CHANGED:
      return {
        ...sharedData,
        active_tab: activeTab.toLowerCase(),
        first_tab_click: firstTabChange,
        interaction_action: 'tab change',
        previous_tab: previousTab.toLowerCase()
      };
    case EVENT_TYPE.ARROW_CLICKED:
      return {
        ...sharedData,
        interaction_action: `${arrowDirection} click`
      };
    case EVENT_TYPE.VIEWED:
    default:
      return {
        ...sharedData,
        event: 'recommendation_view'
      };
  }
};

export const fireTabbedViewEvent = (eventData) => {
  window.dataLayer.push(prepareTabbedViewEventData(eventData));
};

export const fireTabbedViewEventWithCallback = ({callback, eventData}) => {
  const data = prepareTabbedViewEventData(eventData);
  window.dataLayer.push({
    ...data,
    eventCallback: callback,
    eventTimeout: 1500
  });
};

