  RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE,
  RELATED_PRODUCTS_TAB_TRENDING_PRODUCTS
} from 'constants/pdpRelatedProducts';
import useIntersectionObserverOnce from 'hooks/useIntersectionObserverOnce';
import ProductDetailsRow from 'product_details_page/ProductDetailsRow';
import ProductDetailsCard from 'product_details_page/RelatedProducts/RelatedProductCard';
import createRecoCardLinkHref from 'utils/createRecoCardLinkHref';
import {
  EVENT_TYPE,
  fireTabbedViewEvent,
  fireTabbedViewEventWithCallback
